    // --- 音频采样（分带） ---
    // 低频：节奏基底
    float audioLow = texture(iChannel0, vec2(0.05, 0.25)).r;
    // 中频：旋律
    float audioMid = texture(iChannel0, vec2(0.25, 0.5)).r;
    // 高频：细节
    float audioHigh = texture(iChannel0, vec2(0.5, 0.75)).r;

    // 圆舞曲脉冲：用时间模拟3/4拍强弱弱
