            if (phaseOffset < 0.33) beatEffect = 0.6 + 0.4 * pulse;
            else if (phaseOffset < 0.66) beatEffect = 0.8 + 0.2 * pulse;
            else beatEffect = 0.5 + 0.5 * pulse;

